"use client";

import { useState, useEffect } from "react";

interface SearchKeyword {
    id: string;
    baseKeyword: string;
    keywordSuggestion: string;
    keywordType: string;
    isActive: boolean;
    createdAt: Date;
}

export default function KeywordsPage() {
    const [baseKeyword, setBaseKeyword] = useState("");
    const [keywords, setKeywords] = useState<SearchKeyword[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isGenerating, setIsGenerating] = useState(false);
    const [message, setMessage] = useState("");

    // Load keywords from database
    const loadKeywords = async () => {
        setIsLoading(true);
        try {
            const response = await fetch("/api/admin/keywords");
            const data = await response.json();
            setKeywords(data.keywords || []);
        } catch (error) {
            console.error("Failed to load keywords:", error);
            setMessage("Lỗi khi tải danh sách từ khoá");
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadKeywords();
    }, []);

    // Generate keywords using AI
    const generateKeywords = async () => {
        if (!baseKeyword.trim()) {
            setMessage("Vui lòng nhập từ khoá cơ sở");
            return;
        }

        setIsGenerating(true);
        setMessage("Đang tạo từ khoá bằng AI...");

        try {
            const response = await fetch("/api/admin/keywords/generate", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ baseKeyword: baseKeyword.trim() }),
            });

            const data = await response.json();

            if (response.ok) {
                setMessage(`Đã tạo ${data.createdCount} từ khoá!`);
                loadKeywords();
                setBaseKeyword("");
            } else {
                setMessage(data.error || "Lỗi khi tạo từ khoá");
            }
        } catch (error) {
            console.error("Failed to generate keywords:", error);
            setMessage("Lỗi khi tạo từ khoá");
        } finally {
            setIsGenerating(false);
        }
    };

    // Delete keyword
    const deleteKeyword = async (id: string) => {
        try {
            const response = await fetch(`/api/admin/keywords/${id}`, {
                method: "DELETE",
            });

            if (response.ok) {
                setKeywords(keywords.filter((k) => k.id !== id));
                setMessage("Đã xoá từ khoá");
            }
        } catch (error) {
            console.error("Failed to delete keyword:", error);
        }
    };

    // Toggle active status
    const toggleKeyword = async (id: string, currentStatus: boolean) => {
        try {
            const response = await fetch(`/api/admin/keywords/${id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ isActive: !currentStatus }),
            });

            if (response.ok) {
                setKeywords(
                    keywords.map((k) =>
                        k.id === id ? { ...k, isActive: !currentStatus } : k
                    )
                );
            }
        } catch (error) {
            console.error("Failed to toggle keyword:", error);
        }
    };

    // Seed common keywords
    const seedCommonKeywords = async () => {
        setIsGenerating(true);
        setMessage("Đang thêm từ khoá phổ biến...");

        try {
            const response = await fetch("/api/admin/keywords/seed", {
                method: "POST",
            });

            const data = await response.json();

            if (response.ok) {
                setMessage(`Đã thêm ${data.createdCount} từ khoá phổ biến!`);
                loadKeywords();
            } else {
                setMessage(data.error || "Lỗi khi thêm từ khoá");
            }
        } catch (error) {
            console.error("Failed to seed keywords:", error);
            setMessage("Lỗi khi thêm từ khoá");
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div style={{ padding: "2rem", maxWidth: "1200px", margin: "0 auto" }}>
            <h1>Quản lý từ khoá tìm kiếm</h1>

            {message && (
                <div
                    style={{
                        padding: "1rem",
                        marginBottom: "1rem",
                        background: message.includes("Lỗi") ? "#fee" : "#efe",
                        borderRadius: "8px",
                        color: message.includes("Lỗi") ? "#c00" : "#050",
                    }}
                >
                    {message}
                </div>
            )}

            <div
                style={{
                    background: "var(--bg-card)",
                    padding: "1.5rem",
                    borderRadius: "12px",
                    marginBottom: "2rem",
                    border: "1px solid var(--border)",
                }}
            >
                <h2>Tạo từ khoá mới bằng AI</h2>
                <p style={{ color: "var(--text-muted)", marginBottom: "1rem" }}>
                    Nhập từ khoá cơ sở (ví dụ: marketing, developer, design...), AI sẽ tự động tạo
                    các từ khoá gợi ý và từ khoá liên quan.
                </p>
                <div style={{ display: "flex", gap: "1rem", marginBottom: "1rem" }}>
                    <input
                        type="text"
                        placeholder="Nhập từ khoá cơ sở..."
                        value={baseKeyword}
                        onChange={(e) => setBaseKeyword(e.target.value)}
                        style={{
                            flex: 1,
                            padding: "0.75rem",
                            borderRadius: "8px",
                            border: "1px solid var(--border)",
                            fontSize: "1rem",
                        }}
                    />
                    <button
                        onClick={generateKeywords}
                        disabled={isGenerating || !baseKeyword.trim()}
                        style={{
                            padding: "0.75rem 1.5rem",
                            background: "var(--primary)",
                            color: "white",
                            border: "none",
                            borderRadius: "8px",
                            cursor: isGenerating ? "not-allowed" : "pointer",
                            opacity: isGenerating ? 0.7 : 1,
                        }}
                    >
                        {isGenerating ? "Đang tạo..." : "Tạo bằng AI"}
                    </button>
                </div>
                <button
                    onClick={seedCommonKeywords}
                    disabled={isGenerating}
                    style={{
                        padding: "0.5rem 1rem",
                        background: "var(--bg)",
                        color: "var(--text)",
                        border: "1px solid var(--border)",
                        borderRadius: "8px",
                        cursor: isGenerating ? "not-allowed" : "pointer",
                    }}
                >
                    + Thêm từ khoá phổ biến có sẵn
                </button>
            </div>

            <div
                style={{
                    background: "var(--bg-card)",
                    padding: "1.5rem",
                    borderRadius: "12px",
                    border: "1px solid var(--border)",
                }}
            >
                <div
                    style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        marginBottom: "1rem",
                    }}
                >
                    <h2>Danh sách từ khoá ({keywords.length})</h2>
                    <button
                        onClick={loadKeywords}
                        disabled={isLoading}
                        style={{
                            padding: "0.5rem 1rem",
                            background: "var(--bg)",
                            color: "var(--text)",
                            border: "1px solid var(--border)",
                            borderRadius: "8px",
                            cursor: isLoading ? "not-allowed" : "pointer",
                        }}
                    >
                        {isLoading ? "Đang tải..." : "Tải lại"}
                    </button>
                </div>

                <table style={{ width: "100%", borderCollapse: "collapse" }}>
                    <thead>
                        <tr style={{ borderBottom: "1px solid var(--border)" }}>
                            <th style={{ textAlign: "left", padding: "0.75rem" }}>Từ khoá cơ sở</th>
                            <th style={{ textAlign: "left", padding: "0.75rem" }}>Từ khoá gợi ý</th>
                            <th style={{ textAlign: "left", padding: "0.75rem" }}>Loại</th>
                            <th style={{ textAlign: "center", padding: "0.75rem" }}>Trạng thái</th>
                            <th style={{ textAlign: "right", padding: "0.75rem" }}>Hành động</th>
                        </tr>
                    </thead>
                    <tbody>
                        {keywords.length === 0 ? (
                            <tr>
                                <td
                                    colSpan={5}
                                    style={{ textAlign: "center", padding: "2rem", color: "var(--text-muted)" }}
                                >
                                    Chưa có từ khoá nào. Hãy tạo mới!
                                </td>
                            </tr>
                        ) : (
                            keywords.map((keyword) => (
                                <tr
                                    key={keyword.id}
                                    style={{ borderBottom: "1px solid var(--border)" }}
                                >
                                    <td style={{ padding: "0.75rem" }}>{keyword.baseKeyword}</td>
                                    <td style={{ padding: "0.75rem" }}>{keyword.keywordSuggestion}</td>
                                    <td style={{ padding: "0.75rem" }}>
                                        <span
                                            style={{
                                                padding: "0.25rem 0.5rem",
                                                borderRadius: "4px",
                                                fontSize: "0.75rem",
                                                background:
                                                    keyword.keywordType === "keyword_suggestion"
                                                        ? "#e0f2fe"
                                                        : "#f3e8ff",
                                                color:
                                                    keyword.keywordType === "keyword_suggestion"
                                                        ? "#0369a1"
                                                        : "#7c3aed",
                                            }}
                                        >
                                            {keyword.keywordType === "keyword_suggestion"
                                                ? "Gợi ý"
                                                : "Liên quan"}
                                        </span>
                                    </td>
                                    <td style={{ padding: "0.75rem", textAlign: "center" }}>
                                        <button
                                            onClick={() => toggleKeyword(keyword.id, keyword.isActive)}
                                            style={{
                                                padding: "0.25rem 0.75rem",
                                                borderRadius: "4px",
                                                border: "none",
                                                cursor: "pointer",
                                                background: keyword.isActive ? "#dcfce7" : "#fee",
                                                color: keyword.isActive ? "#166534" : "#991b1b",
                                            }}
                                        >
                                            {keyword.isActive ? "Hoạt động" : "Bị tắt"}
                                        </button>
                                    </td>
                                    <td style={{ padding: "0.75rem", textAlign: "right" }}>
                                        <button
                                            onClick={() => deleteKeyword(keyword.id)}
                                            style={{
                                                padding: "0.25rem 0.5rem",
                                                background: "#fee",
                                                color: "#991b1b",
                                                border: "none",
                                                borderRadius: "4px",
                                                cursor: "pointer",
                                            }}
                                        >
                                            Xoá
                                        </button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}
